<div class="d-flex justify-content-between align-items-center mb-3 mobile-stack"><h1 class="page-title h3 mb-0">Produk</h1><a class="btn btn-primary" href="<?= e(url('index.php?page=produk-create')) ?>"><i class="bi bi-plus-circle me-1"></i>Tambah Produk</a></div><div class="card enterprise-card"><div class="card-body p-0"><div class="table-responsive"><table class="table table-hover align-middle mb-0"><thead><tr><th>Produk</th><th>Barcode</th><th>Kategori</th><th>Harga Jual</th><th>Stok</th><th>Status</th><th class="text-end">Aksi</th></tr></thead><tbody><?php foreach($rows as $r): ?><tr><td><div class="d-flex align-items-center gap-3"><img class="product-thumb" src="<?= !empty($r['gambar_produk']) ? e(url($r['gambar_produk'])) : 'https://placehold.co/48x48?text=No' ?>" alt="Produk"><div><div class="fw-semibold"><?= e($r['nama_produk']) ?></div><div class="text-muted small"><?= e($r['kode_produk']) ?> · <?= e($r['nama_satuan']) ?></div></div></div></td><td><?= e($r['barcode'] ?: '-') ?></td><td><?= e($r['nama_kategori']) ?></td><td><?= e(fmt_rp($r['harga_jual'])) ?></td><td><?= e($r['stok']) ?></td><td><span class="badge <?= $r['status']==='aktif' ? 'text-bg-success' : 'text-bg-secondary' ?>"><?= e($r['status']) ?></span></td><td class="text-end"><a class="btn btn-sm btn-warning" href="<?= e(url('index.php?page=produk-edit&id='.$r['id'])) ?>">Edit</a> <a class="btn btn-sm btn-danger" onclick="return confirm('Hapus data?')" href="<?= e(url('index.php?page=produk-delete&id='.$r['id'])) ?>">Hapus</a></td></tr><?php endforeach; ?></tbody></table></div></div></div>